import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import { createAnalyticsRoutes } from '../../src/routes/analytics.routes.js';
import type { RouteDefinition, RouteRequest } from '../../src/routes/types.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';
import type {
  DashboardData,
  MetricDetailResponse,
  TimeSeriesResponse,
  TopProductsResponse,
} from '../../src/models/analytics.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeOrder(overrides: Partial<Order> & { id: string; userId: string }): Order {
  return {
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
    total: 10,
    status: 'pending',
    createdAt: new Date('2025-01-15T12:00:00Z'),
    updatedAt: new Date('2025-01-15T12:00:00Z'),
    ...overrides,
  };
}

function makeUser(overrides: Partial<User> & { id: string }): User {
  return {
    name: 'Test User',
    email: 'test@example.com',
    role: 'member',
    createdAt: new Date('2025-01-15T12:00:00Z'),
    updatedAt: new Date('2025-01-15T12:00:00Z'),
    ...overrides,
  };
}

function makeRequest(overrides: Partial<RouteRequest> = {}): RouteRequest {
  return {
    params: {},
    query: {},
    body: undefined,
    ...overrides,
  };
}

function findRoute(routes: RouteDefinition[], path: string): RouteDefinition {
  const route = routes.find((r) => r.path === path);
  if (!route) throw new Error(`Route not found: ${path}`);
  return route;
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe('Analytics Routes', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;
  let routes: RouteDefinition[];

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
    routes = createAnalyticsRoutes(service);
  });

  // -----------------------------------------------------------------------
  // Route structure
  // -----------------------------------------------------------------------

  describe('route structure', () => {
    it('should create 4 route definitions', () => {
      expect(routes).toHaveLength(4);
    });

    it('should define all expected paths', () => {
      const paths = routes.map((r) => r.path);
      expect(paths).toContain('/api/analytics/dashboard');
      expect(paths).toContain('/api/analytics/metrics/:type');
      expect(paths).toContain('/api/analytics/timeseries');
      expect(paths).toContain('/api/analytics/top-products');
    });

    it('should use GET method for all routes', () => {
      for (const route of routes) {
        expect(route.method).toBe('GET');
      }
    });

    it('should include descriptions for all routes', () => {
      for (const route of routes) {
        expect(route.description).toBeDefined();
        expect(route.description!.length).toBeGreaterThan(0);
      }
    });
  });

  // -----------------------------------------------------------------------
  // GET /api/analytics/dashboard
  // -----------------------------------------------------------------------

  describe('GET /api/analytics/dashboard', () => {
    it('should return 200 with dashboard data', async () => {
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100 }));
      userRepo.save(makeUser({ id: 'u1' }));

      const route = findRoute(routes, '/api/analytics/dashboard');
      const res = await route.handler(makeRequest({
        query: {
          startDate: '2025-01-01T00:00:00Z',
          endDate: '2025-01-31T23:59:59Z',
        },
      }));

      expect(res.status).toBe(200);
      const data = res.data as DashboardData;
      expect(data.metrics).toHaveLength(4);
      expect(data.ordersByStatus).toBeInstanceOf(Array);
      expect(data.revenueTimeSeries).toBeInstanceOf(Array);
      expect(data.query.startDate).toBe('2025-01-01T00:00:00Z');
      expect(data.query.endDate).toBe('2025-01-31T23:59:59Z');
      expect(data.generatedAt).toBeDefined();
    });

    it('should use default date range when not provided', async () => {
      const route = findRoute(routes, '/api/analytics/dashboard');
      const res = await route.handler(makeRequest());

      expect(res.status).toBe(200);
      const data = res.data as DashboardData;
      expect(data.query.startDate).toBeDefined();
      expect(data.query.endDate).toBeDefined();
    });

    it('should pass userId filter to service', async () => {
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 50 }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u2', total: 100 }));

      const route = findRoute(routes, '/api/analytics/dashboard');
      const res = await route.handler(makeRequest({
        query: {
          startDate: '2025-01-01T00:00:00Z',
          endDate: '2025-01-31T23:59:59Z',
          userId: 'u1',
        },
      }));

      expect(res.status).toBe(200);
      const data = res.data as DashboardData;
      const revenue = data.metrics.find((m) => m.type === 'revenue');
      expect(revenue?.value).toBe(50);
    });

    it('should return 400 for invalid startDate', async () => {
      const route = findRoute(routes, '/api/analytics/dashboard');
      const res = await route.handler(makeRequest({
        query: { startDate: 'not-a-date', endDate: '2025-01-31T23:59:59Z' },
      }));

      expect(res.status).toBe(400);
      expect((res.data as { error: string }).error).toContain('Invalid startDate');
    });

    it('should return 400 for invalid endDate', async () => {
      const route = findRoute(routes, '/api/analytics/dashboard');
      const res = await route.handler(makeRequest({
        query: { startDate: '2025-01-01T00:00:00Z', endDate: 'bad-date' },
      }));

      expect(res.status).toBe(400);
      expect((res.data as { error: string }).error).toContain('Invalid endDate');
    });

    it('should return 400 when startDate is after endDate', async () => {
      const route = findRoute(routes, '/api/analytics/dashboard');
      const res = await route.handler(makeRequest({
        query: {
          startDate: '2025-02-01T00:00:00Z',
          endDate: '2025-01-01T00:00:00Z',
        },
      }));

      expect(res.status).toBe(400);
      expect((res.data as { error: string }).error).toContain('startDate must be before endDate');
    });
  });

  // -----------------------------------------------------------------------
  // GET /api/analytics/metrics/:type
  // -----------------------------------------------------------------------

  describe('GET /api/analytics/metrics/:type', () => {
    it('should return 200 with metric detail for valid type', async () => {
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100 }));

      const route = findRoute(routes, '/api/analytics/metrics/:type');
      const res = await route.handler(makeRequest({
        params: { type: 'revenue' },
        query: {
          startDate: '2025-01-01T00:00:00Z',
          endDate: '2025-01-31T23:59:59Z',
        },
      }));

      expect(res.status).toBe(200);
      const data = res.data as MetricDetailResponse;
      expect(data.metric.type).toBe('revenue');
      expect(data.metric.value).toBe(100);
      expect(data.timeSeries).toBeInstanceOf(Array);
      expect(data.generatedAt).toBeDefined();
    });

    it('should return 400 for invalid metric type', async () => {
      const route = findRoute(routes, '/api/analytics/metrics/:type');
      const res = await route.handler(makeRequest({
        params: { type: 'invalid-metric' },
        query: {
          startDate: '2025-01-01T00:00:00Z',
          endDate: '2025-01-31T23:59:59Z',
        },
      }));

      expect(res.status).toBe(400);
      expect((res.data as { error: string }).error).toContain('Invalid metric type');
      expect((res.data as { error: string }).error).toContain('invalid-metric');
    });

    it('should handle all valid metric types', async () => {
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100 }));
      userRepo.save(makeUser({ id: 'u1' }));

      const route = findRoute(routes, '/api/analytics/metrics/:type');
      const types = ['orders', 'revenue', 'users', 'average-order-value'];

      for (const type of types) {
        const res = await route.handler(makeRequest({
          params: { type },
          query: {
            startDate: '2025-01-01T00:00:00Z',
            endDate: '2025-01-31T23:59:59Z',
          },
        }));
        expect(res.status).toBe(200);
        expect((res.data as MetricDetailResponse).metric.type).toBe(type);
      }
    });

    it('should return 400 for invalid date in metric request', async () => {
      const route = findRoute(routes, '/api/analytics/metrics/:type');
      const res = await route.handler(makeRequest({
        params: { type: 'revenue' },
        query: { startDate: 'garbage' },
      }));

      expect(res.status).toBe(400);
      expect((res.data as { error: string }).error).toContain('Invalid startDate');
    });
  });

  // -----------------------------------------------------------------------
  // GET /api/analytics/timeseries
  // -----------------------------------------------------------------------

  describe('GET /api/analytics/timeseries', () => {
    it('should return 200 with time series data', async () => {
      orderRepo.save(makeOrder({
        id: 'o1', userId: 'u1', total: 100,
        createdAt: new Date('2025-01-15T12:00:00Z'),
      }));

      const route = findRoute(routes, '/api/analytics/timeseries');
      const res = await route.handler(makeRequest({
        query: {
          metric: 'revenue',
          granularity: 'day',
          startDate: '2025-01-01T00:00:00Z',
          endDate: '2025-01-31T23:59:59Z',
        },
      }));

      expect(res.status).toBe(200);
      const data = res.data as TimeSeriesResponse;
      expect(data.metric).toBe('revenue');
      expect(data.granularity).toBe('day');
      expect(data.points).toBeInstanceOf(Array);
      expect(data.generatedAt).toBeDefined();
    });

    it('should return 400 when metric is missing', async () => {
      const route = findRoute(routes, '/api/analytics/timeseries');
      const res = await route.handler(makeRequest({
        query: {
          startDate: '2025-01-01T00:00:00Z',
          endDate: '2025-01-31T23:59:59Z',
        },
      }));

      expect(res.status).toBe(400);
      expect((res.data as { error: string }).error).toContain('metric');
    });

    it('should return 400 for invalid metric', async () => {
      const route = findRoute(routes, '/api/analytics/timeseries');
      const res = await route.handler(makeRequest({
        query: {
          metric: 'bogus',
          startDate: '2025-01-01T00:00:00Z',
          endDate: '2025-01-31T23:59:59Z',
        },
      }));

      expect(res.status).toBe(400);
      expect((res.data as { error: string }).error).toContain('metric');
    });

    it('should return 400 for invalid granularity', async () => {
      const route = findRoute(routes, '/api/analytics/timeseries');
      const res = await route.handler(makeRequest({
        query: {
          metric: 'orders',
          granularity: 'millisecond',
          startDate: '2025-01-01T00:00:00Z',
          endDate: '2025-01-31T23:59:59Z',
        },
      }));

      expect(res.status).toBe(400);
      expect((res.data as { error: string }).error).toContain('Invalid granularity');
      expect((res.data as { error: string }).error).toContain('millisecond');
    });

    it('should default granularity to day', async () => {
      const route = findRoute(routes, '/api/analytics/timeseries');
      const res = await route.handler(makeRequest({
        query: {
          metric: 'orders',
          startDate: '2025-01-01T00:00:00Z',
          endDate: '2025-01-03T23:59:59Z',
        },
      }));

      expect(res.status).toBe(200);
      const data = res.data as TimeSeriesResponse;
      expect(data.granularity).toBe('day');
    });

    it('should support all granularity values', async () => {
      const route = findRoute(routes, '/api/analytics/timeseries');
      const granularities = ['hour', 'day', 'week', 'month'];

      for (const granularity of granularities) {
        const res = await route.handler(makeRequest({
          query: {
            metric: 'orders',
            granularity,
            startDate: '2025-01-01T00:00:00Z',
            endDate: '2025-01-31T23:59:59Z',
          },
        }));
        expect(res.status).toBe(200);
        expect((res.data as TimeSeriesResponse).granularity).toBe(granularity);
      }
    });

    it('should return 400 for invalid date in timeseries request', async () => {
      const route = findRoute(routes, '/api/analytics/timeseries');
      const res = await route.handler(makeRequest({
        query: { metric: 'orders', endDate: 'xyz' },
      }));

      expect(res.status).toBe(400);
      expect((res.data as { error: string }).error).toContain('Invalid endDate');
    });
  });

  // -----------------------------------------------------------------------
  // GET /api/analytics/top-products
  // -----------------------------------------------------------------------

  describe('GET /api/analytics/top-products', () => {
    it('should return 200 with top products', async () => {
      orderRepo.save(makeOrder({
        id: 'o1', userId: 'u1', total: 100,
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 25 },
